let contactId = parse.contactIdDirecto || '';

if (!contactId) {
  const lead = (typeof $json.data === 'string') ? JSON.parse($json.data) : ($json || {});
  const contactos = (lead._embedded && lead._embedded.contacts) || [];
  contactos.sort((a, b) => (b.is_main === true) - (a.is_main === true));
  contactId = contactos.length ? String(contactos[0].id) : '';
}

return [{ json: { contactId, refCode: parse.refCode } }];

